parameters.jsCode:
const item = $input.first().json;

// 判斷是 message 還是 callback_query
if (item.callback_query) {
  const cb = item.callback_query;
  return [{
    json: {
      type: 'callback',
      action: cb.data,
      chatId: cb.message.chat.id,
      messageId: cb.message.message_id,
      callbackQueryId: cb.id,
      userId: cb.from.id,
      userName: cb.from.first_name || cb.from.username || 'unknown'
    }
  }];
}

if (item.message) {
  const msg = item.message;
  const text = (msg.text || '').trim();
  if (text === '/panel' || text === '/start' || text === '/menu') {
    return [{
      json: {
        type: 'command',
        action: 'show_panel',
        chatId: msg.chat.id,
        messageId: msg.message_id,
        userId: msg.from.id,
        userName: msg.from.first_name || msg.from.username || 'unknown'
      }
    }];
  }
}

return [];

