parameters.jsCode:
const item = $input.first().json;
const action = item.action;
const chatId = item.chatId;
const callbackQueryId = item.callbackQueryId;
const messageId = item.messageId;
const BOT = `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN || '請設定環境變數'}`;
const TASKBOARD = 'http://localhost:3011';

// 先回應 callback query（避免按鈕轉圈圈）
await fetch(`${BOT}/answerCallbackQuery`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ callback_query_id: callbackQueryId })
});

let replyText = '';
let replyMarkup = null;

switch (action) {
  case 'sys_check': {
    replyText = '🔍 *系統檢查中...*\n\n正在執行 self-heal.sh check，請稍候。\n\n';
    try {
      // 查任務板狀態
      const res = await fetch(`${TASKBOARD}/api/tasks`);
      const data = await res.json();
      const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);
      const running = tasks.filter(t => t.status === 'running' || t.status === 'in_progress');
      const review = tasks.filter(t => t.status === 'review');
      const failed = tasks.filter(t => t.status === 'failed');

      replyText = `📋 *系統檢查結果*\n\n`;
      replyText += `📦 任務總數: ${tasks.length}\n`;
      replyText += `🏃 執行中: ${running.length}\n`;
      replyText += `👀 待審核: ${review.length}\n`;
      replyText += `❌ 失敗: ${failed.length}\n`;

      if (tasks.length > 200) {
        replyText += `\n⚠️ *警告*：任務數量超過 200，可能需要清理！`;
      }
      if (running.length > 3) {
        replyText += `\n⚠️ *警告*：有 ${running.length} 個任務在跑，可能有卡住的！`;
      }
    } catch (e) {
      replyText = `📋 *系統檢查結果*\n\n❌ 任務板連線失敗: ${e.message}\n\n請確認 localhost:3011 是否在跑。`;
    }
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'cleanup': {
    replyText = '🧹 *清理巡檢 (SOP-5)*\n\n';
    replyText += '巡檢項目：\n';
    replyText += '1️⃣ 根目錄非白名單檔案\n';
    replyText += '2️⃣ 隱藏檔 / 未授權程式\n';
    replyText += '3️⃣ 可疑目錄\n';
    replyText += '4️⃣ 任務板衛生\n';
    replyText += '5️⃣ 近期活動偵測\n\n';
    replyText += '⚠️ 此操作需要在 CLI 執行：\n';
    replyText += '`./scripts/self-heal.sh check`\n\n';
    replyText += '選擇操作：';
    replyMarkup = {
      inline_keyboard: [
        [
          { text: '🔍 只檢查', callback_data: 'cleanup_check' },
          { text: '🔧 檢查+修復', callback_data: 'cleanup_fix' }
        ],
        [{ text: '🔙 返回面板', callback_data: 'show_panel' }]
      ]
    };
    break;
  }

  case 'cleanup_check': {
    replyText = '🔍 *執行 self-heal.sh check*\n\n';
    try {
      const res = await fetch(`${TASKBOARD}/api/tasks`);
      const data = await res.json();
      const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);
      const running = tasks.filter(t => t.status === 'running' || t.status === 'in_progress');
      const stale = running.filter(t => {
        if (!t.updatedAt) return false;
        const hours = (Date.now() - new Date(t.updatedAt).getTime()) / 3600000;
        return hours > 24;
      });

      replyText += `📊 任務板衛生：\n`;
      replyText += `• 總任務: ${tasks.length}\n`;
      replyText += `• 執行中: ${running.length}\n`;
      replyText += `• 卡住 (>24h): ${stale.length}\n\n`;

      if (stale.length > 0) {
        replyText += `⚠️ 卡住的任務：\n`;
        stale.slice(0, 5).forEach(t => {
          replyText += `• ${t.title || t.id} (${t.status})\n`;
        });
      }

      replyText += `\n✅ 任務板檢查完成`;
      replyText += `\n\n💡 完整檢查請在 CLI 執行：\n\`./scripts/self-heal.sh check\``;
    } catch (e) {
      replyText += `❌ 任務板連線失敗: ${e.message}`;
    }
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'cleanup_fix': {
    replyText = '🔧 *清理修復*\n\n';
    replyText += '⚠️ 自動修復需要在 CLI 執行：\n\n';
    replyText += '```\n./scripts/self-heal.sh fix\n```\n\n';
    replyText += '這會自動：\n';
    replyText += '• 移除非白名單的根目錄檔案\n';
    replyText += '• 清理未授權自動化檔案\n';
    replyText += '• 修復卡住的任務狀態\n\n';
    replyText += '🔴 *注意*：修復操作是 🔴 紅燈，需要主人批准。';
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'task_status': {
    try {
      const res = await fetch(`${TASKBOARD}/api/tasks`);
      const data = await res.json();
      const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

      const byStatus = {};
      tasks.forEach(t => {
        const s = t.status || 'unknown';
        byStatus[s] = (byStatus[s] || 0) + 1;
      });

      replyText = `📊 *任務狀態總覽*\n\n`;
      replyText += `📦 總數: ${tasks.length}\n\n`;

      const statusEmoji = {
        'queued': '⏳', 'running': '🏃', 'in_progress': '🏃',
        'review': '👀', 'done': '✅', 'failed': '❌',
        'cancelled': '🚫', 'blocked': '🔒'
      };

      Object.entries(byStatus).sort((a, b) => b[1] - a[1]).forEach(([status, count]) => {
        const emoji = statusEmoji[status] || '📌';
        replyText += `${emoji} ${status}: ${count}\n`;
      });

      // 最近 5 個任務
      const recent = tasks.sort((a, b) => {
        return new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0);
      }).slice(0, 5);

      if (recent.length > 0) {
        replyText += `\n📋 *最近更新：*\n`;
        recent.forEach(t => {
          const emoji = statusEmoji[t.status] || '📌';
          const title = (t.title || t.id || '-').substring(0, 30);
          replyText += `${emoji} ${title}\n`;
        });
      }
    } catch (e) {
      replyText = `📊 *任務狀態*\n\n❌ 連線失敗: ${e.message}`;
    }
    replyMarkup = {
      inline_keyboard: [
        [
          { text: '👀 待審核', callback_data: 'tasks_review' },
          { text: '🏃 執行中', callback_data: 'tasks_running' }
        ],
        [{ text: '🔙 返回面板', callback_data: 'show_panel' }]
      ]
    };
    break;
  }

  case 'tasks_review': {
    try {
      const res = await fetch(`${TASKBOARD}/api/tasks?status=review`);
      const data = await res.json();
      const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

      if (tasks.length === 0) {
        replyText = '👀 *待審核任務*\n\n目前沒有待審核的任務。';
      } else {
        replyText = `👀 *待審核任務 (${tasks.length})*\n\n`;
        tasks.slice(0, 10).forEach((t, i) => {
          replyText += `${i+1}. *${(t.title || t.id || '-').substring(0, 40)}*\n`;
          if (t.assignee) replyText += `   👤 ${t.assignee}\n`;
        });
      }
    } catch (e) {
      replyText = `👀 *待審核*\n\n❌ 連線失敗: ${e.message}`;
    }
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'tasks_running': {
    try {
      const res = await fetch(`${TASKBOARD}/api/tasks?status=running`);
      const data = await res.json();
      let tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

      // 也查 in_progress
      try {
        const res2 = await fetch(`${TASKBOARD}/api/tasks?status=in_progress`);
        const data2 = await res2.json();
        const tasks2 = Array.isArray(data2) ? data2 : (data2.data || data2.tasks || []);
        tasks = tasks.concat(tasks2);
      } catch(e) {}

      if (tasks.length === 0) {
        replyText = '🏃 *執行中任務*\n\n目前沒有正在執行的任務。';
      } else {
        replyText = `🏃 *執行中任務 (${tasks.length})*\n\n`;
        tasks.slice(0, 10).forEach((t, i) => {
          const title = (t.title || t.id || '-').substring(0, 40);
          replyText += `${i+1}. *${title}*\n`;
          if (t.assignee) replyText += `   👤 ${t.assignee}\n`;
          if (t.updatedAt) {
            const hours = Math.round((Date.now() - new Date(t.updatedAt).getTime()) / 3600000);
            if (hours > 24) replyText += `   ⚠️ 已跑 ${hours}h（可能卡住）\n`;
          }
        });
      }
    } catch (e) {
      replyText = `🏃 *執行中*\n\n❌ 連線失敗: ${e.message}`;
    }
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'progress': {
    try {
      const res = await fetch(`${TASKBOARD}/api/tasks?status=done`);
      const data = await res.json();
      const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

      // 最近完成的
      const recent = tasks.sort((a, b) => {
        return new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0);
      }).slice(0, 10);

      replyText = `📝 *進度報告*\n\n`;
      replyText += `✅ 已完成任務: ${tasks.length}\n\n`;

      if (recent.length > 0) {
        replyText += `*最近完成：*\n`;
        recent.forEach((t, i) => {
          const title = (t.title || t.id || '-').substring(0, 40);
          const date = t.updatedAt ? new Date(t.updatedAt).toLocaleDateString('zh-TW') : '-';
          replyText += `${i+1}. ${title} (${date})\n`;
        });
      } else {
        replyText += '目前還沒有完成的任務。';
      }
    } catch (e) {
      replyText = `📝 *進度報告*\n\n❌ 連線失敗: ${e.message}`;
    }
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'emergency_stop': {
    replyText = '🛑 *緊急停止*\n\n';
    replyText += '確定要發出緊急停止指令嗎？\n\n';
    replyText += '這會：\n';
    replyText += '• 通知所有 Agent 立即停止\n';
    replyText += '• 凍結任務板狀態\n';
    replyText += '• 等待主人說「繼續」才恢復';
    replyMarkup = {
      inline_keyboard: [
        [
          { text: '🛑 確認停止', callback_data: 'confirm_stop' },
          { text: '❌ 取消', callback_data: 'show_panel' }
        ]
      ]
    };
    break;
  }

  case 'confirm_stop': {
    try {
      // 發送停止事件到系統
      await fetch('http://127.0.0.1:5678/webhook/system-event-notify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          source: 'telegram-panel',
          event: 'emergency_stop',
          message: '🛑 主人透過 Telegram 面板發出緊急停止指令',
          timestamp: new Date().toISOString()
        })
      });
    } catch (e) {
      // webhook 可能沒在跑，不影響
    }

    replyText = '🛑 *緊急停止已發出*\n\n';
    replyText += '✅ 停止指令已廣播\n';
    replyText += '⏸️ 所有 Agent 應立即停止\n\n';
    replyText += '說「繼續」或按下方按鈕恢復：';
    replyMarkup = {
      inline_keyboard: [
        [{ text: '▶️ 恢復運作', callback_data: 'resume_ops' }],
        [{ text: '🔙 返回面板', callback_data: 'show_panel' }]
      ]
    };
    break;
  }

  case 'resume_ops': {
    try {
      await fetch('http://127.0.0.1:5678/webhook/system-event-notify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          source: 'telegram-panel',
          event: 'resume',
          message: '▶️ 主人透過 Telegram 面板恢復運作',
          timestamp: new Date().toISOString()
        })
      });
    } catch (e) {}

    replyText = '▶️ *已恢復運作*\n\n所有 Agent 可以繼續工作。';
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'reload_rules': {
    replyText = '🔄 *重載規範*\n\n';
    replyText += '提醒達爾重新讀取：\n';
    replyText += '• AGENTS.md v1.4\n';
    replyText += '• SOP-1 ~ SOP-10\n';
    replyText += '• CR-1 ~ CR-7\n\n';
    replyText += '💡 在達爾對話中貼 `05-規範總覽.md` 的內容即可。';
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'help': {
    replyText = '📖 *達爾控制面板 - 指令清單*\n\n';
    replyText += '*Telegram 指令：*\n';
    replyText += '/panel - 開啟控制面板\n';
    replyText += '/start - 開啟控制面板\n';
    replyText += '/menu - 開啟控制面板\n\n';
    replyText += '*面板按鈕：*\n';
    replyText += '📋 系統檢查 - 查任務板狀態\n';
    replyText += '🧹 清理巡檢 - SOP-5 巡檢流程\n';
    replyText += '📊 任務狀態 - 任務統計 + 明細\n';
    replyText += '📝 進度報告 - 最近完成的任務\n';
    replyText += '🛑 緊急停止 - 停止所有 Agent\n';
    replyText += '🔄 重載規範 - 提醒重讀規範\n\n';
    replyText += '*CLI 指令（終端機）：*\n';
    replyText += '`./scripts/self-heal.sh check` - 完整檢查\n';
    replyText += '`./scripts/self-heal.sh fix` - 自動修復\n';
    replyText += '`./scripts/self-heal.sh cr7` - 偵測未授權自動化\n\n';
    replyText += '*燈號：* 🟢 直接做 🟡 先說 🔴 等批准';
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
    break;
  }

  case 'show_panel': {
    // 更新原訊息為面板
    await fetch(`${BOT}/editMessageText`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: chatId,
        message_id: messageId,
        text: '🔧 *達爾控制面板*\n\n選擇要執行的操作：',
        parse_mode: 'Markdown',
        reply_markup: {
          inline_keyboard: [
            [
              { text: '📋 系統檢查', callback_data: 'sys_check' },
              { text: '🧹 清理巡檢', callback_data: 'cleanup' }
            ],
            [
              { text: '📊 任務狀態', callback_data: 'task_status' },
              { text: '📝 進度報告', callback_data: 'progress' }
            ],
            [
              { text: '🛑 緊急停止', callback_data: 'emergency_stop' },
              { text: '🔄 重載規範', callback_data: 'reload_rules' }
            ],
            [
              { text: '📖 指令清單', callback_data: 'help' }
            ]
          ]
        }
      })
    });
    return [{ json: { done: true, action: 'panel_shown' } }];
  }

  default:
    replyText = `⚠️ 未知操作: ${action}`;
    replyMarkup = { inline_keyboard: [[{ text: '🔙 返回面板', callback_data: 'show_panel' }]] };
}

// 編輯原訊息（取代轉圈圈）
await fetch(`${BOT}/editMessageText`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    chat_id: chatId,
    message_id: messageId,
    text: replyText,
    parse_mode: 'Markdown',
    reply_markup: replyMarkup
  })
});

return [{ json: { done: true, action: action } }];
